// ========================================================================
// MinIO S3 Upload — Drop-in replacement for broken awsS3 V2 upload node
// Uses AWS Signature V4 with Node.js http + crypto (zero external deps)
//
// INPUT (from previous node):
//   $json.fileKey      — S3 object key, e.g. '40_Timeline_Weekly/Daily/2026-04-04.md'
//   $json.fileContent  — string content to upload
//   $json.bucket       — (optional) bucket name, default 'obsidian-vault'
//   $json.contentType  — (optional) MIME type, default 'text/markdown; charset=utf-8'
//
// OUTPUT:
//   { success, fileKey, bucket, etag, size, verified }
// ========================================================================
const crypto = require('crypto');
const http = require('http');

// ---- CONFIGURATION (edit these for your MinIO instance) ----
const MINIO_HOST = '192.168.1.240';
const MINIO_PORT = 9000;
const ACCESS_KEY = '[REDACTED_MINIO_ACCESS_KEY]';
const SECRET_KEY = '[REDACTED_MINIO_SECRET_KEY]';
const REGION = 'us-east-1';
// -------------------------------------------------------------

const BUCKET = $json.bucket || 'obsidian-vault';
const KEY = $json.fileKey;
const CONTENT_TYPE = $json.contentType || 'text/markdown; charset=utf-8';
const body = Buffer.from($json.fileContent, 'utf-8');

if (!KEY) throw new Error('fileKey is required');
if (!$json.fileContent && $json.fileContent !== '') throw new Error('fileContent is required');

// ---- AWS V4 Signing ----
function hmac(key, data, enc) {
  const h = crypto.createHmac('sha256', key).update(data, 'utf8');
  return enc ? h.digest(enc) : h.digest();
}
function sha256(data, enc) {
  return crypto.createHash('sha256').update(data).digest(enc || 'hex');
}
function signingKey(secret, ds, region, svc) {
  return hmac(hmac(hmac(hmac('AWS4' + secret, ds), region), svc), 'aws4_request');
}

const now = new Date();
const amzDate = now.toISOString().replace(/[-:]/g, '').replace(/\.\d+Z$/, 'Z');
const dateStamp = amzDate.substring(0, 8);
const payloadHash = sha256(body, 'hex');
const encodedKey = KEY.split('/').map(s => encodeURIComponent(s)).join('/');
const path = `/${BUCKET}/${encodedKey}`;
const host = `${MINIO_HOST}:${MINIO_PORT}`;

// Build canonical request
const hdrs = {
  'content-length': String(body.length),
  'content-type': CONTENT_TYPE,
  'host': host,
  'x-amz-content-sha256': payloadHash,
  'x-amz-date': amzDate
};
const sortedKeys = Object.keys(hdrs).sort();
const canonicalHeaders = sortedKeys.map(k => `${k}:${hdrs[k]}`).join('\n') + '\n';
const signedHeaders = sortedKeys.join(';');

const canonicalRequest = ['PUT', path, '', canonicalHeaders, signedHeaders, payloadHash].join('\n');
const scope = `${dateStamp}/${REGION}/s3/aws4_request`;
const stringToSign = ['AWS4-HMAC-SHA256', amzDate, scope, sha256(canonicalRequest, 'hex')].join('\n');
const sk = signingKey(SECRET_KEY, dateStamp, REGION, 's3');
const signature = hmac(sk, stringToSign, 'hex');
const auth = `AWS4-HMAC-SHA256 Credential=${ACCESS_KEY}/${scope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;

// ---- HTTP PUT ----
async function httpRequest(method, reqPath, reqHeaders, reqBody) {
  return new Promise((resolve, reject) => {
    const req = http.request({
      hostname: MINIO_HOST, port: MINIO_PORT, path: reqPath, method,
      headers: reqHeaders
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve({ statusCode: res.statusCode, headers: res.headers, body: data }));
    });
    req.on('error', reject);
    if (reqBody) req.write(reqBody);
    req.end();
  });
}

// Upload
const putResult = await httpRequest('PUT', path, { ...hdrs, 'Authorization': auth }, body);

if (putResult.statusCode < 200 || putResult.statusCode >= 300) {
  throw new Error(`MinIO PUT failed [${putResult.statusCode}]: ${putResult.body}`);
}

// ---- Verified write: HEAD to confirm ----
const headDate = new Date();
const headAmzDate = headDate.toISOString().replace(/[-:]/g, '').replace(/\.\d+Z$/, 'Z');
const headDateStamp = headAmzDate.substring(0, 8);
const headPayload = sha256('', 'hex');
const headHdrs = {
  'host': host,
  'x-amz-content-sha256': headPayload,
  'x-amz-date': headAmzDate
};
const headSorted = Object.keys(headHdrs).sort();
const headCanonical = headSorted.map(k => `${k}:${headHdrs[k]}`).join('\n') + '\n';
const headSignedH = headSorted.join(';');
const headCR = ['HEAD', path, '', headCanonical, headSignedH, headPayload].join('\n');
const headScope = `${headDateStamp}/${REGION}/s3/aws4_request`;
const headSTS = ['AWS4-HMAC-SHA256', headAmzDate, headScope, sha256(headCR, 'hex')].join('\n');
const headSK = signingKey(SECRET_KEY, headDateStamp, REGION, 's3');
const headSig = hmac(headSK, headSTS, 'hex');
const headAuth = `AWS4-HMAC-SHA256 Credential=${ACCESS_KEY}/${headScope}, SignedHeaders=${headSignedH}, Signature=${headSig}`;

const headResult = await httpRequest('HEAD', path, { ...headHdrs, 'Authorization': headAuth });

return [{ json: {
  success: true,
  verified: headResult.statusCode === 200,
  fileKey: KEY,
  bucket: BUCKET,
  etag: putResult.headers?.etag || headResult.headers?.etag || 'unknown',
  size: body.length,
  contentType: CONTENT_TYPE,
  statusCode: putResult.statusCode,
  verifyStatusCode: headResult.statusCode
}}];
